WebLink.url:
{!REQUIRESCRIPT("/soap/ajax/23.0/connection.js")} 
{!REQUIRESCRIPT("/soap/ajax/23.0/apex.js")} 

var records = {!GETRECORDIDS($ObjectType.Contact)}; 

if (records.length <= 0) {
alert('You must select at least 1 Candidate.'); 
} else {

var contactsIds = records.join(','); 

var resultItem = new sforce.SObject("ts2__s_ResultItem__c");
if (resultItem) {
resultItem.ts2__sel_contact_id_list__c = contactsIds;
var createRiResult = sforce.connection.create([resultItem]);
if (createRiResult && createRiResult[0].getBoolean("success")) {
var resultId = createRiResult[0].id;
var url = "/apex/ts2__email_manager?cId=" + resultId + '&src=resultitem';
var features = 'directories=no,menubar=no,titlebar=no,toolbar=no,width=800,height=600';
win = window.open(url,'', features);
win.focus();
}
}
}
